\displaystyle{\begin{aligned}
   {\frac{5}{\frac{6}{y}+\frac{3}{y-5}}} 
      \amp = {\frac{5}{\frac{6}{y}+\frac{3}{y-5}}} \cdot \frac{{y\mathopen{}\left(y-5\right)}}{{y\mathopen{}\left(y-5\right)}} \\
      \amp = {\frac{5y\mathopen{}\left(y-5\right)}{\frac{6}{y}y\mathopen{}\left(y-5\right)+\frac{3}{y-5}y\mathopen{}\left(y-5\right)}} \\
      \amp = {\frac{5y\mathopen{}\left(y-5\right)}{6\mathopen{}\left(y-5\right)+3y}}, y\ne 0 \text{ and } y\ne 5 \\
      \amp = {\frac{5y\mathopen{}\left(y-5\right)}{6y-30+3y}}, y\ne 0 \text{ and } y\ne 5 \\
      \amp = \frac{5 y (y-5)}{9 y - 30}, y \ne 0 \text{ and } y \ne 5 \\
      \amp = {\frac{5y\mathopen{}\left(y-5\right)}{3\mathopen{}\left(3y-10\right)}, y\ne 0\hbox{ and }y\ne 5}
\end{aligned}
    }
